#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

vector<int> preOrderTraverse(TreeNode* root) {
   if (root == nullptr) return vector<int>();
   vector<int> res;
   res.push_back(root->val);
   res.insert(res.end(), preOrderTraverse(root->left).begin(), preOrderTraverse(root->left).end());
   res.insert(res.end(), preOrderTraverse(root->right).begin(), preOrderTraverse(root->right).end());
   return res;
}

int diameterOfBinaryTree(TreeNode* root) {
   if (root == nullptr) return 0;
   int leftHeight = treeDepth(root->left);
   int rightHeight = treeDepth(root->right);
   int diam = 0;
   for (TreeNode* node : preOrderTraverse(root)) {
      diam = max(diam, leftHeight + rightHeight + 1);
   }
   return diam;
}

int treeDepth(TreeNode* root) {
   if (root == nullptr) return 0;
   return 1 + max(treeDepth(root->left), treeDepth(root->right));
}

